  ('fire-eq-tech-moex-02690', 'fire-eq-tech', 'fire-eq-tech-moex-099-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '自然發火係指物質發生化學反應，反應熱蓄積致使溫度上升，使達到物質的著火溫度。以下何者不屬於 自然發火？', '["活性碳作為吸著劑，產生熱積蓄", "雨水侵入存有大量還原鐵粉之倉庫，使鐵粉產生氧化", "含有聚合防止劑的反應槽中混入不純物", "裝載有不慎將硝銨肥料和麵粉混放的貨輪"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "2166e65ae0a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
